import { useEffect, useState } from 'react';
import api from '../api/client';

export default function TicketList({
  refreshKey = 0,
}) {
  // TICKETS
  const [tickets, setTickets] =
    useState([]);

  // FILTER STATES
  const [
    ticketIdSearch,
    setTicketIdSearch,
  ] = useState('');

  const [
    departmentFilter,
    setDepartmentFilter,
  ] = useState('');

  const [
    divisionSearch,
    setDivisionSearch,
  ] = useState('');

  const [
    moduleFilter,
    setModuleFilter,
  ] = useState('');

  const [
    submoduleFilter,
    setSubmoduleFilter,
  ] = useState('');

  const [status, setStatus] =
    useState('');

  const [
  createdDate,
  setCreatedDate,
] = useState('');

const [
  closedDate,
  setClosedDate,
] = useState('');

  // DROPDOWNS
  const [
    departments,
    setDepartments,
  ] = useState([]);

  const [modules, setModules] =
    useState([]);

  const [
    submodules,
    setSubmodules,
  ] = useState([]);

  // PAGINATION
  const [page, setPage] =
    useState(1);

  const [count, setCount] =
    useState(0);

  const [nextPage, setNextPage] =
    useState(null);

  const [
    previousPage,
    setPreviousPage,
  ] = useState(null);

  // LOAD DROPDOWNS
  const loadDropdowns =
    async () => {
      try {
        const [
          deptRes,
          moduleRes,
          submoduleRes,
        ] = await Promise.all([
          api.get(
            '/masters/departments/'
          ),
          api.get(
            '/masters/modules/'
          ),
          api.get(
            '/masters/submodules/'
          ),
        ]);

        setDepartments(
          deptRes.data.results ||
            deptRes.data ||
            []
        );

        setModules(
          moduleRes.data.results ||
            moduleRes.data ||
            []
        );

        setSubmodules(
          submoduleRes.data.results ||
            submoduleRes.data ||
            []
        );
      } catch (err) {
        console.error(
          'Dropdown load failed:',
          err
        );
      }
    };

  // FILTER MODULES
  const filteredModules =
    !departmentFilter
      ? modules
      : modules.filter(
          (module) =>
            Number(
              module.department_id
            ) ===
            Number(
              departmentFilter
            )
        );

  // FILTER SUBMODULES
  const filteredSubmodules =
    !moduleFilter
      ? submodules
      : submodules.filter(
          (submodule) =>
            Number(
              submodule.module
            ) ===
            Number(
              moduleFilter
            )
        );

  // LOAD TICKETS
  const loadTickets =
    async (pageNo = page) => {
      try {
        const params = {
          page: pageNo,
        };

        if (ticketIdSearch)
          params.ticket_id =
            ticketIdSearch;

        if (departmentFilter)
          params.department =
            departmentFilter;

        if (divisionSearch)
          params.division_name =
            divisionSearch;

        if (moduleFilter)
          params.module =
            moduleFilter;

        if (submoduleFilter)
          params.submodule =
            submoduleFilter;

        if (status)
          params.status =
            status;

        const res =
          await api.get(
            '/tickets/',
            { params }
          );

        const data =
          res.data;

        setTickets(
          data.results || []
        );

        setCount(
          data.count || 0
        );

        setNextPage(
          data.next
        );

        setPreviousPage(
          data.previous
        );
      } catch (err) {
        console.error(
          'Ticket load failed:',
          err
        );
      }
    };

  // INITIAL LOAD
  useEffect(() => {
    loadDropdowns();
  }, []);

  // LOAD TICKETS
  useEffect(() => {
    loadTickets(page);
  }, [
    refreshKey,
    page,
    ticketIdSearch,
    departmentFilter,
    divisionSearch,
    moduleFilter,
    submoduleFilter,
    status,
  ]);

  // RESET FILTERS
  const handleResetFilters =
    () => {
      setTicketIdSearch('');
      setDepartmentFilter(
        ''
      );
      setDivisionSearch('');
      setModuleFilter('');
      setSubmoduleFilter(
        ''
      );
      setStatus('');
      setPage(1);
    };

  const totalPages =
    Math.ceil(count / 8);

  return (
    <div>
      {/* FILTERS */}
      <div className="row mb-3 g-2">
        <div className="col-md-2">
          <input
            type="text"
            className="form-control"
            placeholder="Ticket ID"
            value={
              ticketIdSearch
            }
            onChange={(e) =>
              setTicketIdSearch(
                e.target.value
              )
            }
          />
        </div>

        <div className="col-md-2">
          <select
            className="form-select"
            value={
              departmentFilter
            }
            onChange={(e) => {
              setDepartmentFilter(
                e.target.value
              );
              setModuleFilter('');
              setSubmoduleFilter(
                ''
              );
            }}
          >
            <option value="">
              All Departments
            </option>

            {departments.map(
              (dept) => (
                <option
                  key={dept.id}
                  value={dept.id}
                >
                  {
                    dept.department_name
                  }
                </option>
              )
            )}
          </select>
        </div>

        <div className="col-md-2">
          <select
            className="form-select"
            value={moduleFilter}
            onChange={(e) => {
              setModuleFilter(
                e.target.value
              );
              setSubmoduleFilter(
                ''
              );
            }}
          >
            <option value="">
              All Modules
            </option>

            {filteredModules.map(
              (module) => (
                <option
                  key={module.id}
                  value={module.id}
                >
                  {
                    module.module_name
                  }
                </option>
              )
            )}
          </select>
        </div>

        <div className="col-md-2">
          <select
            className="form-select"
            value={
              submoduleFilter
            }
            onChange={(e) =>
              setSubmoduleFilter(
                e.target.value
              )
            }
          >
            <option value="">
              All Submodules
            </option>

            {filteredSubmodules.map(
              (
                submodule
              ) => (
                <option
                  key={
                    submodule.id
                  }
                  value={
                    submodule.id
                  }
                >
                  {
                    submodule.submodule_name
                  }
                </option>
              )
            )}
          </select>
        </div>
        {/* CREATED DATE */}
<div className="col-md-2">
  <input
    type="date"
    className="form-control"
    value={createdDate}
    onChange={(e) =>
      setCreatedDate(
        e.target.value
      )
    }
  />
</div>

{/* CLOSED DATE */}
<div className="col-md-2">
  <input
    type="date"
    className="form-control"
    value={closedDate}
    onChange={(e) =>
      setClosedDate(
        e.target.value
      )
    }
  />
</div>

        <div className="col-md-2">
          <button
            className="btn btn-secondary w-100"
            onClick={
              handleResetFilters
            }
          >
            Reset
          </button>
        </div>
      </div>

      {/* TICKETS TABLE */}
      <div className="table-responsive">
        <table className="table table-bordered table-striped">
          <thead>
            <tr>
              <th>Ticket ID</th>
              <th>Department</th>
              <th>Module</th>
              <th>Submodule</th>
              <th>Subject</th>
              <th>Status</th>
            </tr>
          </thead>

          <tbody>
            {tickets.length >
            0 ? (
              tickets.map(
                (ticket) => (
                  <tr
                    key={
                      ticket.id
                    }
                  >
                    <td>
                      {
                        ticket.ticket_id
                      }
                    </td>
                    <td>
                      {
                        ticket.department_name
                      }
                    </td>
                    <td>
                      {
                        ticket.module_name
                      }
                    </td>
                    <td>
                      {
                        ticket.submodule_name
                      }
                    </td>
                    <td>
                      {
                        ticket.subject
                      }
                    </td>
                    <td>
                      {
                        ticket.status
                      }
                    </td>
                  </tr>
                )
              )
            ) : (
              <tr>
                <td
                  colSpan="6"
                  className="text-center"
                >
                  No tickets found
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* PAGINATION */}
      <div className="d-flex justify-content-between mt-3">
        <button
          className="btn btn-outline-secondary"
          disabled={!previousPage}
          onClick={() =>
            setPage(
              (prev) =>
                prev - 1
            )
          }
        >
          Previous
        </button>

        <span>
          Page {page} of{' '}
          {totalPages || 1}
        </span>

        <button
          className="btn btn-outline-secondary"
          disabled={!nextPage}
          onClick={() =>
            setPage(
              (prev) =>
                prev + 1
            )
          }
        >
          Next
        </button>
      </div>
    </div>
  );
}
